int p063_fibfib(int n)
/*@ Require
        0 <= n && n < 100 &&
        problem_63_pre(n) &&
        fibfib_step_int_range(n)
    Ensure
        problem_63_spec(n, __return) && emp
*/
{
    if (n == 0) {
        return 0;
    }
    if (n == 1) {
        return 0;
    }
    if (n == 2) {
        return 1;
    }

    int a = 0;
    int b = 0;
    int c = 1;
    int next;
    int i;

    for (i = 3; i <= n; i++) {
        next = a + b + c;
        a = b;
        b = c;
        c = next;
    }
    return c;
}

